import{_ as e,o as r,c as o,a5 as a}from"./chunks/framework.B5tqjWbr.js";const p=JSON.parse('{"title":"学习记录 #0018：保护机制设计——UPS安全的最后防线","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0018：保护机制设计——UPS安全的最后防线","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第18课 — 保护机制设计（Phase 3系统集成） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0018-protection-mechanism.md","filePath":"content/power/archive/old-learning-records/0018-protection-mechanism.md","lastUpdated":null}'),n={name:"content/power/archive/old-learning-records/0018-protection-mechanism.md"};function s(i,t,l,c,d,g){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="学习记录-0018-保护机制设计——ups安全的最后防线" tabindex="-1">学习记录 #0018：保护机制设计——UPS安全的最后防线 <a class="header-anchor" href="#学习记录-0018-保护机制设计——ups安全的最后防线" aria-label="Permalink to &quot;学习记录 #0018：保护机制设计——UPS安全的最后防线&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第18课 — 保护机制设计（Phase 3系统集成） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>3层保护体系</strong>：硬件(μs级)→软件快速(10~100μs)→软件慢速(ms~s级)</li><li><strong>硬件保护</strong>：比较器+TZ引脚，MCU死机也能保护，One-Shot模式</li><li><strong>驱动IC自保护</strong>：DESAT检测+UVLO+有源钳位+米勒钳位</li><li><strong>短路vs过载</strong>：短路&gt;200%+μs级+硬件+手动复位；过载110~200%+ms级+软件反时限</li><li><strong>过温降额</strong>：线性降额公式Pout=Prated×(Tshutdown-T)/(Tshutdown-Tderate)</li><li><strong>故障记录</strong>：环形缓冲区+故障快照（电流/电压/温度/状态）+NVRAM持久化</li><li><strong>故障诊断</strong>：多参数关联分析（INV过流+母线欠压→输出短路）</li><li><strong>设计哲学</strong>：UPS保供电优先（过载→旁路），电机保安全优先（过载→关断）</li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第19课：通信协议与远程监控</p>',6)])])}const m=e(n,[["render",s]]);export{p as __pageData,m as default};
